import React, { useState, useRef, useCallback } from 'react';
import './index.css';

const API_BASE = 'http://127.0.0.1:8000';

const genres = [
  { id: 'rock', name: 'Rock' },
  { id: 'pop', name: 'Pop' },
  { id: 'jazz', name: 'Jazz' },
  { id: 'classical', name: 'Classical' },
  { id: 'hip-hop', name: 'Hip-Hop' },
  { id: 'electronic', name: 'Electronic' },
  { id: 'indie', name: 'Indie' },
  { id: 'r&b', name: 'R&B' },
  { id: 'country', name: 'Country' },
  { id: 'metal', name: 'Metal' },
  { id: 'latin', name: 'Latin' },
  { id: 'folk', name: 'Folk' },
];

const moods = [
  { id: 'happy', name: 'Happy', emoji: '☀' },
  { id: 'energetic', name: 'Energetic', emoji: '⚡' },
  { id: 'relaxing', name: 'Relaxing', emoji: '🌊' },
  { id: 'romantic', name: 'Romantic', emoji: '💜' },
  { id: 'sad', name: 'Sad', emoji: '🌧' },
  { id: 'focus', name: 'Focus', emoji: '🎯' },
  { id: 'party', name: 'Party', emoji: '🎉' },
  { id: 'workout', name: 'Workout', emoji: '💪' },
  { id: 'chill', name: 'Chill', emoji: '😌' },
];

function App() {
  const [selectedGenre, setSelectedGenre] = useState(null);
  const [selectedMood, setSelectedMood] = useState(null);
  const [selectedArtist, setSelectedArtist] = useState('');
  const [songCount, setSongCount] = useState(10);
  const [playlist, setPlaylist] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showEmpty, setShowEmpty] = useState(true);
  
  // Audio player state
  const audioRef = useRef(null);
  const [currentSongId, setCurrentSongId] = useState(null);
  const [isPlaying, setIsPlaying] = useState(false);

  const togglePlayPause = useCallback((songId, previewUrl) => {
    if (currentSongId === songId) {
      // Toggle current song
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play();
      }
    } else {
      // Stop current song and play new one
      if (audioRef.current) {
        audioRef.current.pause();
      }
      
      const audio = new Audio(previewUrl);
      audioRef.current = audio;
      audio.play().catch(e => console.error('Audio play failed:', e));
      setCurrentSongId(songId);
      setIsPlaying(true);
    }
  }, [currentSongId, isPlaying]);

  const handleGenerate = async () => {
    if (!selectedGenre && !selectedMood && !selectedArtist) {
      setError('Please select at least one preference');
      return;
    }

    // Stop current audio
    if (audioRef.current) {
      audioRef.current.pause();
    }
    setCurrentSongId(null);
    setIsPlaying(false);

    setLoading(true);
    setError(null);
    setShowEmpty(false);
    setPlaylist([]);

    try {
      const params = new URLSearchParams();
      if (selectedGenre) params.append('genre', selectedGenre);
      if (selectedMood) params.append('mood', selectedMood);
      if (selectedArtist) params.append('artist', selectedArtist);
      params.append('limit', songCount);

      const response = await fetch(`${API_BASE}/custom?${params}`);
      const data = await response.json();

      setPlaylist(data.playlist || []);
    } catch (err) {
      setError('Failed to generate playlist');
    } finally {
      setLoading(false);
    }
  };

  const defaultArtwork = 'data:image/svg+xml;base64,';

  return (
    <div className="app">
      {/* Your existing UI structure */}
      {playlist.map((song, index) => (
        <div key={index} className="song-card">
          <img src={song.artwork || defaultArtwork} alt={song.title} />
          <div className="song-info">
            <h4>{song.title}</h4>
            <p>{song.artist}</p>
          </div>
          {song.preview_url && (
            <button 
              className={`play-btn ${currentSongId === index ? (isPlaying ? 'playing' : 'paused') : ''}`}
              onClick={() => togglePlayPause(index, song.preview_url)}
            >
              {currentSongId === index && isPlaying ? '⏸️' : '▶️'}
            </button>
          )}
        </div>
      ))}
    </div>
  );
}

export default App;
